+        decide_and_record(
+            &mut ledger,
+            RuntimeMode::Strict,
+            CompatibilityClass::KnownCompatible,
+            0.1,
+            0.5,
+            "first",
+        );
+        decide_and_record(
+            &mut ledger,
+            RuntimeMode::Hardened,
+            CompatibilityClass::Unknown,
+            0.9,
+            0.5,
+            "second",
+        );
+        decide_and_record(
+            &mut ledger,
+            RuntimeMode::Hardened,
+            CompatibilityClass::KnownCompatible,
